const body = $input.first().json.body;
const record = body.record;

return [{ json: {
  produto_id: record.produto_id,
  cliente_nome: record.cliente_nome,
  cliente_whatsapp: record.cliente_whatsapp,
  foto_url: record.foto_url ?? null,
  produto_titulo: record.produto_titulo ?? null,
  produto_disponivel: record.produto_disponivel ?? true,
  produto_marca: record.produto_marca ?? null
}}];

const rawData = $input.first().json;
const produto = Array.isArray(rawData) ? rawData[0] : rawData;
const dados = $('Extrair Dados').first().json;

let phone = dados.cliente_whatsapp.replace(/\D/g, '');
if (phone.length === 10 || phone.length === 11) phone = '55' + phone;
if (phone.length === 12 && phone.startsWith('55')) phone = phone.slice(0,4) + '9' + phone.slice(4);

const fmt = (v) => 'R$ ' + parseFloat(v).toFixed(2).replace('.', ',');

// Tipo do produto
const ehRepresentacao = !dados.produto_disponivel && dados.produto_marca !== null;
const ehSobEncomenda  = !dados.produto_disponivel && dados.produto_marca === null;
const ehProntaEntrega =  dados.produto_disponivel;

// Preço exibido: sempre o preço original
const precoExibido = produto.preco_original || produto.preco;
let precoLinha = '';
if (precoExibido) {
  precoLinha = `\n💰 *Valor: ${fmt(precoExibido)}*`;
}

// Horário de atendimento
const nowBRT = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const day = nowBRT.getDay();
const t = nowBRT.getHours() * 60 + nowBRT.getMinutes();
const manha = t >= 7*60+30 && t < 11*60+30;
const tarde = t >= 13*60+15 && t < (day === 5 ? 17*60 : 18*60);
const aberto = day >= 1 && day <= 5 && (manha || tarde);

const horarioBloco = aberto
  ? ``
  : `\n⏰ *Horário de atendimento:*\n` +
    `Seg a Qui: 7h30–11h30 / 13h15–18h\n` +
    `Sex: 7h30–11h30 / 13h15–17h\n` +
    `Sáb, Dom e Feriados: fechado\n`;

// Mensagem para o CLIENTE
let msgCliente = '';

if (ehRepresentacao) {
  msgCliente =
    `Olá, *${dados.cliente_nome}*! 👋\n\n` +
    `Você demonstrou interesse em:\n` +
    `📦 *${dados.produto_titulo}* (${dados.produto_marca})` +
    precoLinha + `\n\n` +
    `Este é um produto de representação — entraremos em contato para confirmar disponibilidade e prazo de entrega.\n\n` +
    `Em breve nossa equipe fala com você! 🏭`;
} else if (ehSobEncomenda) {
  msgCliente =
    `Olá, *${dados.cliente_nome}*! 👋\n\n` +
    `Você demonstrou interesse em:\n` +
    `📦 *${dados.produto_titulo}*` +
    precoLinha + `\n\n` +
    `Fabricamos este produto sob encomenda — entraremos em contato para confirmar detalhes e prazo de fabricação.\n\n` +
    `Em breve nossa equipe fala com você! 🏭`;
} else {
  msgCliente =
    `Olá, *${dados.cliente_nome}*! 👋\n\n` +
    `Você demonstrou interesse em:\n` +
    `📦 *${dados.produto_titulo}*` +
    precoLinha + `\n\n` +
    `📍 *Retire na fábrica:*\n` +
    `Pousinox — Pouso Alegre, MG\n` +
    `📌 https://maps.app.goo.gl/bNAwCL7Jz4n3pJZx8` +
    horarioBloco +
    `\n⚡ *Estoque limitado — garanta o seu antes que acabe.*\n\n` +
    `Qualquer dúvida estamos à disposição. 😊`;
}

// Tipo para notificação interna
const tipoLabel = ehRepresentacao
  ? `Representação (${dados.produto_marca})`
  : ehSobEncomenda
  ? 'Sob encomenda'
  : 'Pronta entrega';

const msgMarco =
  `🔔 *Novo interesse no Outlet!*\n\n` +
  `📦 *Produto:* ${dados.produto_titulo}\n` +
  `🏷️ *Tipo:* ${tipoLabel}\n` +
  `👤 *Cliente:* ${dados.cliente_nome}\n` +
  `📱 *WhatsApp:* ${dados.cliente_whatsapp}` +
  (produto.preco ? `\n💰 *Preço:* ${fmt(produto.preco)}` : '');

const now = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

return [{ json: {
  phone_cliente: phone,
  phone_marco: '5535998260760',
  msg_cliente: msgCliente,
  msg_marco: msgMarco,
  foto_url: dados.foto_url ?? null,
  sheet_phone: (() => { const d = dados.cliente_whatsapp.replace(/\D/g, ''); const l = d.startsWith('55') && d.length >= 12 ? d.slice(2) : d; return l.length === 11 ? `(${l.slice(0,2)}) ${l.slice(2,7)}-${l.slice(7)}` : l.length === 10 ? `(${l.slice(0,2)}) ${l.slice(2,6)}-${l.slice(6)}` : dados.cliente_whatsapp; })(),
  sheet_name: dados.cliente_nome,
  sheet_tag: dados.produto_titulo,
  sheet_timestamp: now,
  produto_id: dados.produto_id,
  produto_preco: produto.preco_original || produto.preco || 0,
  desconto_max: produto.desconto_max || 0,
  seminovo: produto.seminovo || false,
  descricao: produto.descricao || '',
  specs: produto.specs || null,
  produto_marca: produto.marca || dados.produto_marca || null
}}];
